import{_ as i,o as e,c as a,O as o}from"./chunks/framework.c4f51971.js";const u=JSON.parse('{"title":"版本路线","description":"","frontmatter":{},"headers":[],"relativePath":"product/editions.md","filePath":"product/editions.md","lastUpdated":1775626713000}'),t={name:"product/editions.md"};function d(r,l,c,p,n,s){return e(),a("div",null,l[0]||(l[0]=[o('<h1 id="版本路线" tabindex="-1">版本路线 <a class="header-anchor" href="#版本路线" aria-label="Permalink to &quot;版本路线&quot;">​</a></h1><p>SmartFlow 的版本路线不是单纯“菜单越来越多”，而是平台角色逐步变化：</p><p><code>1.0</code> 先解决交付与可信执行，<code>2.0</code> 解决标准产品化，<code>3.0</code> 解决第三方生态，<code>4.0</code> 解决更广泛的能力包、边缘执行和设备插件治理。</p><h2 id="_1-0-可信-ai-执行交付版" tabindex="-1"><code>1.0</code>：可信 AI 执行交付版 <a class="header-anchor" href="#_1-0-可信-ai-执行交付版" aria-label="Permalink to &quot;`1.0`：可信 AI 执行交付版&quot;">​</a></h2><p>一句话：</p><p><strong>让平台可以直接拿去交付客户、治理多租户、运营免费入口，并通过 CLI 拉通本地脚本接入。</strong></p><p>当前版本路线已经纳入的方向：</p><ul><li>一个客户一个租户</li><li>脚本注册与 Skill 映射</li><li>智能大脑推荐、确认、执行、审计</li><li>平台模板分发、安装、回滚、日志</li><li>公告投放与已读状态</li><li>免费用户治理台账</li><li><code>smartflow-cli register / run</code> 最小闭环</li></ul><p>这一阶段的重点，不是讲最大的故事，而是让平台真实可交付、可运行、可复用。</p><h2 id="_2-0-标准产品化版" tabindex="-1"><code>2.0</code>：标准产品化版 <a class="header-anchor" href="#_2-0-标准产品化版" aria-label="Permalink to &quot;`2.0`：标准产品化版&quot;">​</a></h2><p>一句话：</p><p><strong>把交付能力和免费入口收敛成标准产品，形成免费版、团队版、企业版的正式产品阶梯。</strong></p><p>重点包括：</p><ul><li>套餐与配额产品化</li><li>团队版产品化</li><li>模板与技能包产品化</li><li>CLI + 本地 Agent 正式产品化</li><li>订单、转化、活跃度标准化</li><li>从“项目能交付”走向“产品可标准售卖”</li></ul><p>这一阶段要解决的核心问题，是如何把已有能力包装成真正能持续运营的产品。</p><h2 id="_3-0-生态开放版" tabindex="-1"><code>3.0</code>：生态开放版 <a class="header-anchor" href="#_3-0-生态开放版" aria-label="Permalink to &quot;`3.0`：生态开放版&quot;">​</a></h2><p>一句话：</p><p><strong>把平台从自营交付产品升级成可让第三方接入、审核、分发、交易、共建的生态平台。</strong></p><p>重点包括：</p><ul><li>开发者接入</li><li>模板 / 技能市场</li><li>审核与上架</li><li>API / SDK / 文档中心</li><li>第三方分发与双边生态</li></ul><p>这一阶段的变化，不是“再多做几个后台页面”，而是平台开始承接第三方。</p><h2 id="_4-0-智能执行基础设施版" tabindex="-1"><code>4.0</code>：智能执行基础设施版 <a class="header-anchor" href="#_4-0-智能执行基础设施版" aria-label="Permalink to &quot;`4.0`：智能执行基础设施版&quot;">​</a></h2><p>一句话：</p><p><strong>把平台从“脚本与 Skill 调度系统”进一步升级成可治理更广泛能力包、边缘执行端和设备插件的智能执行基础设施。</strong></p><p>公开规划重点包括：</p><ul><li>把能力单元从脚本 / Skill 继续扩展到插件包、设备动作包、边缘能力包</li><li>用统一控制面管理安装、升级、回滚、授权和审计</li><li>把 Web 控制面、CLI、本地 Agent、边缘节点继续收敛到同一套治理逻辑</li><li>支持更复杂的执行位置，例如本地环境、边缘节点和未来的设备执行端</li><li>在更高风险场景下继续坚持权限控制、规则约束、审计追踪和人工确认</li></ul><h3 id="为什么-4-0-不是空想" tabindex="-1">为什么 <code>4.0</code> 不是空想 <a class="header-anchor" href="#为什么-4-0-不是空想" aria-label="Permalink to &quot;为什么 `4.0` 不是空想&quot;">​</a></h3><p><code>4.0</code> 并不是重新造一个完全不同的平台，它延续的是同一套核心逻辑：</p><ul><li>能力要先注册，才能被调度</li><li>执行要有权限边界和风险控制</li><li>安装、升级、回滚都要可追踪</li><li>控制面和执行端要统一治理，而不是各跑各的</li></ul><p>从这个角度看，今天的脚本注册、Skill 调度、模板安装、日志审计，都是未来设备插件和边缘能力治理的前置基础。</p><h3 id="_4-0-可能承接的公开场景" tabindex="-1"><code>4.0</code> 可能承接的公开场景 <a class="header-anchor" href="#_4-0-可能承接的公开场景" aria-label="Permalink to &quot;`4.0` 可能承接的公开场景&quot;">​</a></h3><ul><li>边缘节点上的任务执行</li><li>设备能力包管理</li><li>本地 Agent 与设备执行端联动</li><li>需要统一控制面的多执行端系统</li></ul><p><code>4.0</code> 的重点不是“先做机器人故事”，而是把当前平台抽象成一套更稳定、更通用的能力治理底座。</p><h2 id="为什么企业线和免费版要并行" tabindex="-1">为什么企业线和免费版要并行 <a class="header-anchor" href="#为什么企业线和免费版要并行" aria-label="Permalink to &quot;为什么企业线和免费版要并行&quot;">​</a></h2><p>只做企业线的问题：</p><ul><li>增长依赖人工接单</li><li>用户反馈样本不足</li></ul><p>只做免费线的问题：</p><ul><li>交付场景不足</li><li>现金流不足</li></ul><p>所以当前路线保持为：</p><p><strong>企业交付 <code>1.0</code> 承接收入，个人免费版承接入口，两条线共用同一套可信执行底座。</strong></p><h2 id="当前公开节奏" tabindex="-1">当前公开节奏 <a class="header-anchor" href="#当前公开节奏" aria-label="Permalink to &quot;当前公开节奏&quot;">​</a></h2><p>对外当前最准确的说法是：</p><ul><li><code>1.0</code> 是当前已经成立的交付主线</li><li><code>2.0</code> 是下一阶段的标准产品化</li><li><code>3.0</code> 是开发者与市场生态</li><li><code>4.0</code> 是更长期的智能执行基础设施方向</li></ul>',43)]))}const m=i(t,[["render",d]]);export{u as __pageData,m as default};
